          // ── Cosmic age ↔ star distribution ──

          function getAgeDistribution(age) {

            var t = Math.max(0, Math.min(14, age));

            var early = Math.max(0, 1 - t / 5);

            var late = Math.min(1, t / 8);

            return [

              0.003 + early * 0.05,

              0.13 + early * 1.5,

              0.6 + early * 3.0,

              3 + early * 4.0,

              7.6 - late * 2,

              12.1 + late * 3,

              76.5 + late * 10

            ];

          }



