                  ptGlow.addColorStop(1, 'hsla(' + ((pi * 25 + canvas._brainTick) % 360) + ', 80%, 65%, 0)');

                  ctx.beginPath(); ctx.arc(px2, py2, 6, 0, Math.PI * 2);

