                ctx.quadraticCurveTo(W * 0.75, H * 0.28, W * 0.72, H * 0.38);

                ctx.strokeStyle = '#8b7faa'; ctx.lineWidth = 0.8; ctx.stroke();

                ctx.setLineDash([]); ctx.strokeStyle = '#a78bfa'; ctx.lineWidth = 2;



                // Additional sulci (precentral, postcentral)

