          var canvasRef = window._econCanvasRef;



          // ── Supply & Demand State ──

          var sdDemandShift = d.sdDemandShift || 0;

          var sdSupplyShift = d.sdSupplyShift || 0;

          var sdPriceFloor = d.sdPriceFloor || 0;

          var sdPriceCeiling = d.sdPriceCeiling || 0;

          var sdTax = d.sdTax || 0;



