              var dx = mx - dragStartX;

              plates[dragIdx].x = Math.max(0, Math.min(cW - plates[dragIdx].w, dragPlateStartX + dx));

              plates[dragIdx].vx = dx > 0 ? 1 : dx < 0 ? -1 : 0;

